import { ethers } from "ethers";

async function swapTokens(provider, privateKey, tokenAAddress, tokenBAddress, dexAddress, amountIn) {
  const wallet = new ethers.Wallet(privateKey, provider);
  const tokenA = new ethers.Contract(tokenAAddress, ERC20_ABI, wallet);
  const tokenB = new ethers.Contract(tokenBAddress, ERC20_ABI, wallet);
  const dex = new ethers.Contract(dexAddress, DEX_ABI, wallet);

  // Approve max amount for convenience
  await tokenA.approve(dexAddress, ethers.constants.MaxUint256);

  // Swap tokens
  const tx = await dex.swap(tokenAAddress, tokenBAddress, amountIn);
  await tx.wait();

  console.log("Tokens swapped successfully!");
}

